"""
MKT Original Language Commentary — 1 Kings chapters 6–7
Run: python3 scripts/zc-original-1kings-6-7.py

Ch6: Construction of the Temple — 480th-year anchor, perfect-cube Holy of Holies,
     Eden imagery (cherubim/palms/flowers), conditional covenant (vv12-13),
     7-year completion echoing creation's 7 days
Ch7: Temple furnishings and palace complex — palace > temple in size (inversion signal),
     Hiram filled with wisdom like Bezalel (Exod 31), Jachin/Boaz pillar names,
     the molten Sea on 12 oxen, Davidic treasures transferred

Key term decisions:
- debîr rendered 'inner sanctuary' (not 'oracle' or 'most holy place') — etymology debated
- ʿōlām in v13 = 'will not abandon' — not merely future but covenant permanence
- Yāḵîn / Bōʿaz rendered as names (transliterated) — their semantic force noted in commentary
- yām (molten sea) = 'the Sea' (capitalized) — cosmic symbolic weight of the term
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS1 = {
  "6": {
    "1": "<p><strong>ûḇišnat haʾarbaʿ meʾôṯ wᵉšᵉmônîm</strong>: 'In the four hundred and eightieth year' — the chronological anchor for Solomonic history. The 480 years from the Exodus to the fourth year of Solomon (ca. 966 BCE) is structurally significant: 480 = 12 × 40, twelve generations of forty years each — the biblical measure of a complete generational period (Num 32:13; Judg 3:11). The number marks the Temple's founding as the culmination of the covenant era that began with the Exodus. The theological point is not a mathematical cipher but a declaration: the Temple is the goal toward which the Exodus covenant was moving.</p>",
    "2": "<p><strong>šiššîm ʾammāh ʾorkô wᵉʿeśrîm rōḥab wᵉšᵉlōšîm qômāṯô</strong>: '60 cubits long, 20 cubits wide, 30 cubits high' — the Temple's dimensions establish the main hall (<em>hêḵāl</em>). A cubit (<em>ʾammāh</em>) is approximately 18 inches (45 cm), making the main hall roughly 90 × 30 × 45 feet. The dimensions are approximately twice those of the Mosaic tabernacle's dimensions (30 × 10 × 10 cubits for the tabernacle proper), preserving the same 3:1 length-to-width ratio. The Temple is an enlargement of the tabernacle, not a replacement; continuity in proportion encodes continuity in theological function.</p>",
    "3": "<p><strong>ûlām</strong>: 'portico/porch/vestibule' — the frontal entry hall. The three-zone structure of the Temple (ʾûlām, hêḵāl, debîr) mirrors the three-zone structure of the Mosaic tabernacle (outer court, holy place, most holy place) and the graduated approach from public to private to most intimate. The ʾûlām's width equaled the full width of the Temple (20 cubits) and projected 10 cubits forward, forming the visible public face of the building.</p>",
    "4": "<p><strong>ḥallônê šᵉqûpîm ʾăṭûmîm</strong>: 'windows of fixed lattice-work' — the Temple had recessed lattice windows that admitted light while maintaining privacy. The term <em>šᵉqûpîm</em> (from <em>šāqap</em>, to look out) appears elsewhere for peering through (Gen 26:8; Judg 5:28), while <em>ʾăṭûmîm</em> can mean 'stopped' or 'framed.' These architecturally distinctive openings mark the threshold between ordinary and sacred space.</p>",
    "5": "<p><strong>yāṣîaʿ</strong>: 'side chamber/annex' — the three-story side-rooms surrounding the main building on three sides (all except the front). These chambers were attached to the outer wall without penetrating it (v6): no breach was made in the Temple's primary walls. The side chambers provided storage and perhaps priestly quarters while insulating the sacred core.</p>",
    "6": "<p><strong>migraʿôṯ</strong>: 'offsets/ledges' — the Temple's outer wall was built in three steps, each story's floor resting on a ledge (rebate) in the wall. This eliminated the need to embed beams into the sacred wall itself (v7), maintaining the wall's integrity. The architectural detail is noted to explain how the annex attached without structural violation of the Temple's primary enclosure.</p>",
    "7": "<p><strong>ʾăḇānîm šᵉlēmôṯ massāʿ nibᵉneh</strong>: 'complete/finished stones from the quarry it was built' — the stones were dressed before arriving at the Temple Mount. <em>Šālem</em> (complete, perfect) also carries the sense of wholeness or peace (<em>šālôm</em>). No hammer (<em>maqāḇôṯ</em>), axe (<em>gārzēn</em>), or iron tool (<em>kᵉlî barzel</em>) was heard at the building site. The silence is a sacred threshold marker: the work of fashioning is completed elsewhere; at the sacred site only assembly occurs. Iron implements signify warfare and violence in OT symbology (cf. the altar's uncut stones, Exod 20:25; Deut 27:5) — the house of the God of peace is built in silence and without weapons.</p>",
    "8": "<p><strong>petaḥ haṣṣēlāʿ</strong>: 'the entrance of the middle floor/side-chambers' — the architectural access point to the three levels of side rooms. The side chambers were accessed from the right (south) side of the Temple via a staircase arrangement going up from floor to floor, confirming the three-story arrangement described in vv5-6.</p>",
    "9": "<p><strong>wayyibᵉn ʾeṯ-habbayiṯ wayyᵉkallēhû</strong>: 'He built the house and completed it' — verse 9 reports the completion of the main structure's walls and roof (cedar beams and planks). <em>Kālāh</em> (to complete, finish) is used here in a partial sense — the outer structure is complete before the interior work begins (vv14ff). The cedar roof capped the stone walls, completing the primary enclosure.</p>",
    "10": "<p><strong>hayyāṣîaʿ… ʿeśer bāʾammāh gōḇhô</strong>: 'the side-chambers…five cubits high each' — the verse confirms the annex dimensions (5 cubits per story, three stories = 15 cubits total height) and that the cedar beams of the annex attached to the main Temple walls. The structural repetition underscores the care taken to document the Temple's construction accurately from official building accounts.</p>",
    "11": "<p><strong>wayᵉhî dᵉḇar YHWH ʾel-šᵉlōmōh</strong>: 'And the word of YHWH came to Solomon' — mid-construction, YHWH interrupts with a conditional promise. The word (<em>dāḇār</em>) of YHWH intrudes into the building project to assert the theological condition governing the Temple's efficacy. The timing is significant: not before construction begins (which would make the promise appear unconditional) and not after completion (too late to function as warning). The word comes during the work, reshaping the meaning of what is being built.</p>",
    "12": "<p><strong>ʾim-tēlēk bᵉḥuqqōṯay</strong>: 'If you walk in my statutes' — the Davidic covenant's temple-provision is conditional on obedience. While the eternal dynasty was unconditionally promised to David (2 Sam 7:14-16), the Temple's ongoing function as YHWH's dwelling depends on Solomon's (and his successors') faithfulness. <em>Ḥuqqôṯ</em> (statutes), <em>mišpāṭîm</em> (ordinances), <em>miṣwôṯ</em> (commandments) — the triad of covenant obligation terminology makes clear that the Temple does not replace the covenant's behavioral expectations. The later destruction of the Temple (2 Kgs 25) is the fulfillment of this condition's violation.</p>",
    "13": "<p><strong>wᵉšāḵantî bᵉṯôḵ bᵉnê yiśrāʾēl wᵉlōʾ ʾeʿᵉzōḇ ʾeṯ-ʿammî yiśrāʾēl</strong>: 'I will dwell in the midst of the children of Israel and I will not abandon my people Israel' — the Temple's purpose stated: not to house a deity (ancient Near Eastern temples were divine palaces where the god was fed) but to provide the dwelling-point of YHWH's presence among his people. The negation <em>wᵉlōʾ ʾeʿᵉzōḇ</em> (I will not abandon/forsake) uses the covenantal <em>ʿāzaḇ</em> — the same verb in Deut 31:6, Josh 1:5, and Heb 13:5. The promise is relational, not architectural: the Temple exists to facilitate divine-human dwelling, not to confine God (cf. 8:27).</p>",
    "14": "<p><strong>wayyibᵉn šᵉlōmōh ʾeṯ-habbayiṯ wayyᵉkallēhû</strong>: 'So Solomon built the house and completed it' — verse 14 repeats the completion formula from v9, now framing the summary after the divine interlude of vv11-13. The repetition marks a structural boundary: vv1-13 = construction overview and divine word; vv14ff = interior furnishing details. The narrative moves from the external shell to the interior treatment (cedar paneling, olive wood carvings, gold overlay).</p>",
    "15": "<p><strong>bᵉḵiṯlôṯ ḥāllôṯ ʿaṣê ʾārāzîm</strong>: 'boards of cedar wood' — the interior was completely paneled with cedar (<em>ʾerez</em>, the prized cedar of Lebanon), covering all stone walls from floor to ceiling. The cedar paneling concealed all the stone, making the interior entirely an organic wooden structure overlaid with gold. No stone was visible within the sacred space — a deliberate contrast with the stone altars and monuments of Canaanite worship.</p>",
    "16": "<p><strong>wayyibᵉn ʿeśrîm ʾammāh miyrᵉḵeṯê habbayiṯ bᵉṣalʿôṯ ʾarāzîm</strong>: 'He built twenty cubits from the rear of the house with cedar planks' — the rear 20 cubits of the Temple were floored and walled with cedar from floor to ceiling, creating the separate inner sanctuary (<em>debîr</em>). The cedar floor-to-ceiling partition enclosed the Holy of Holies as a completely wood-paneled chamber within the larger building. The 20-cubit demarcation turns the rear third of the Temple's length into the most sacred zone.</p>",
    "17": "<p><strong>wᵉhabbayiṯ hûʾ hêḵāl lifᵉnāyw ʾarbaʿîm bāʾammāh</strong>: 'And the house — the main hall before it — forty cubits' — verse 17 clarifies the spatial division: the main hall (<em>hêḵāl</em>) = 40 cubits; the inner sanctuary (<em>debîr</em>) = 20 cubits; together = 60 cubits (the full length established in v2). The <em>hêḵāl</em> (main hall/nave) derives from the Akkadian <em>ekallu</em> (palace), reflecting the ancient Near Eastern convention that a god's temple was the god's palace.</p>",
    "18": "<p><strong>ʾereẓ ʾel-habbayiṯ penîmāh</strong>: 'cedar toward the inside of the house' — the cedar was carved with gourds (<em>pᵉqāʿîm</em>) and open flowers (<em>pᵉṭûrê ṣîṣîm</em>). The botanical imagery on every interior surface was intentional: the Temple's interior recreated the garden of Eden — the sacred space where God and humans had walked together before the fall. The gourd motif appears also on the bronze Sea (7:24) and on the high priest's robe (Exod 28:33).</p>",
    "19": "<p><strong>wᵉhaddebîr bᵉṯôḵ habbayiṯ mippᵉnîmāh hēkîn</strong>: 'He prepared the inner sanctuary in the innermost part of the house' — <em>debîr</em> (the inner sanctuary) is the term for the Holy of Holies. Its etymology is disputed: possibly from <em>dāḇār</em> (word/oracle) — the place where YHWH speaks; or from an Ugaritic root meaning 'back room.' The LXX renders it <em>to hagion ton hagion</em> (holy of holies). Its purpose is stated: to receive the ark of the covenant — it is the ark's permanent throne room.</p>",
    "20": "<p><strong>wᵉhaddebîr ʿeśrîm ʾammāh ʾorkô wᵉʿeśrîm ʾammāh rōḥab wᵉʿeśrîm ʾammāh qômāṯô</strong>: '20 cubits long, 20 cubits wide, 20 cubits high' — the Holy of Holies is a perfect cube. A cube is the only shape where all dimensions are equal — it represents divine perfection and completeness. The New Jerusalem (Rev 21:16) is also a perfect cube (12,000 stadia on each side), signaling that it is the eschatological fulfillment of what the Holy of Holies anticipated: the cosmic dwelling of God with his people where the cube-shape expands to fill all creation. Gold overlay (<em>zāhāb sāgûr</em>, refined/pure gold) covered every surface.</p>",
    "21": "<p><strong>wayyᵉṣap šᵉlōmōh ʾeṯ-habbayiṯ mippᵉnîmāh zāhāḇ sāgûr</strong>: 'Solomon overlaid the interior of the house with pure gold' — <em>sāgûr</em> (refined/locked/pure) gold is the highest grade, used for the most sacred furnishings (the lampstand, Exod 25:31; the mercy seat, Exod 25:17). Cedar chains were drawn across the front of the Holy of Holies as symbolic barriers before the veil. Every visible interior surface was gold — anticipating the divine <em>kāḇôd</em> (glory) that would fill the completed building (8:10-11).</p>",
    "22": "<p><strong>wᵉḵol-habbayiṯ ṣippāh zāhāḇ</strong>: 'The whole house he overlaid with gold' — v22 summarizes the gold overlay covering the entire interior, including the altar belonging to the inner sanctuary (<em>hammizḇēaḥ ʾăšer laddebîr</em>). This cedar altar, distinct from the bronze altar in the outer court, stood before the entrance to the Holy of Holies overlaid with gold. The completeness of the gold overlay makes the entire interior a luminous golden space.</p>",
    "23": "<p><strong>wayyas ̣ baddebîr šᵉnê kᵉrûḇîm ʿaṣê šāmen</strong>: 'In the inner sanctuary he made two cherubim of olive wood' — <em>kᵉrûḇîm</em> (cherubim) are the winged divine attendants who guard the divine presence (Gen 3:24: cherubim guard Eden's entrance; Exod 25:18-20: cherubim on the mercy seat). <em>ʿAṣê šāmen</em> is olive wood — the oiliest, densest wood available in the region, associated with blessing and anointing. Each cherub was 10 cubits (15 feet) tall — enormous guardians in the Temple's most sacred space.</p>",
    "24": "<p><strong>ḥāmēš ʾammôṯ kᵉnaṣ hakkᵉrûḇ hāʾeḥāḏ</strong>: 'Five cubits was one wing of the cherub' — each cherub had a wingspan of 10 cubits (two wings × 5 cubits each). The two cherubim standing side by side spanned the full 20-cubit width of the Holy of Holies. Each figure was 10 cubits tall with a 10-cubit wingspan — the same dimension for height and wingspan, creating a proportionally balanced guardian and filling the Holy of Holies from wall to wall.</p>",
    "25": "<p><strong>wᵉhakkᵉrûḇ haššēnî ʿeśer bāʾammāh</strong>: 'The second cherub was ten cubits' — v25 confirms that both cherubim were identical (same dimensions, same measure, same form). The precision of the description — twice stated — ensures the symmetry of divine honor: neither cherub was greater. The parallel dimensions reflect the literary concern for sacred exactness that marks the entire Temple-building narrative and echoes Exodus 25-31.</p>",
    "26": "<p><strong>qômāṯ hakkᵉrûḇ hāʾeḥāḏ ʿeśer bāʾammāh ûḵēn hakkᵉrûḇ haššēnî</strong>: 'The height of one cherub was ten cubits, and likewise the second cherub' — the redundant confirmation of equal height is typical of the Temple narrative's precision. The cherubim's 10-cubit height made them approximately 15 feet tall — they dominated the 20-cubit-high (30-foot) chamber. The visual effect: golden walls, golden cherubim 15 feet tall with 30-foot combined wingspan, and the ark beneath their outstretched wings.</p>",
    "27": "<p><strong>wayyittēn ʾeṯ-hakkᵉrûḇîm bᵉṯôḵ habbayiṯ happᵉnîmî</strong>: 'He placed the cherubim in the inner house' — the cherubim's wing-tips touched the opposing walls (each outer wing) and each other (each inner wing), creating a continuous 20-cubit canopy from wall to wall. The ark sat beneath the intersection of their inner wings (8:6-7). The cherubim formed the living throne of YHWH — the Temple architecture embodied YHWH <em>yōšēḇ hakkᵉrûḇîm</em> (who sits enthroned upon the cherubim; 1 Sam 4:4; Ps 80:1).</p>",
    "28": "<p><strong>wayyᵉṣap šᵉlōmōh ʾeṯ-hakkᵉrûḇîm zāhāḇ</strong>: 'Solomon overlaid the cherubim with gold' — the olive-wood cherubim were covered with gold, as were all surfaces of the inner sanctuary. This gold-on-olive-wood composite combines the practical (structural olive wood) with the symbolic (gold overlay for sacred representation). The olive wood beneath the gold may carry a secondary association: olive oil is the medium of anointing (<em>māšîaḥ</em>, anointed one) — the cherubim are made of wood associated with consecration, then consecrated further with gold overlay.</p>",
    "29": "<p><strong>wᵉʾēṯ kol-qîrôṯ habbayiṯ mᵉsaḇîḇ qallāʿ pᵉtûḥôṯ tîmōrōṯ ûpᵉṭûrê ṣîṣîm</strong>: 'On all the walls of the house around, both inner and outer rooms, he carved engravings of cherubim, palm trees, and open flowers' — the three elements of the carved program create an Eden environment: cherubim (the divine guardians of God's garden-presence, Gen 3:24), palm trees (<em>tîmōrôṯ</em>, the tall graceful trees of the promised land's abundance), and open flowers (<em>pᵉṭûrê ṣîṣîm</em>, blossoming life). The Temple's interior decoration deliberately recreates the garden of Eden — the primordial sacred space where divine and human presence cohabited — framing every act of worship within the narrative of paradise lost and the hope of paradise restored.</p>",
    "30": "<p><strong>wᵉʾeṯ-qarkāʿ habbayiṯ ṣippāh zāhāḇ</strong>: 'The floor of the house he overlaid with gold' — even the floor received gold overlay, completing the all-gold interior. The effect: standing inside the Temple, every surface in every direction — above, below, left, right — was gold. The space was designed to overwhelm the senses with the visual language of divine glory.</p>",
    "31": "<p><strong>wᵉʾeṯ-petaḥ haddebîr ʿāśāh daltôṯ ʿaṣê šāmen</strong>: 'For the entrance of the inner sanctuary he made doors of olive wood' — the <em>debîr</em>'s entrance had a five-sided door frame (<em>mezûzāh</em>, <em>ḥamēšîṯ</em>). The door construction — olive wood (same as the cherubim) with carved cherubim, palms, and flowers overlaid with hammered gold — maintained the Eden imagery to the very threshold of the most sacred space. The five-sided (pentagonal) frame is unusual and may reflect a distinctive architectural feature of the inner sanctuary's entrance.</p>",
    "32": "<p><strong>wᵉqālaʿ ʿălêhem kᵉrûḇîm wᵉtîmōrōṯ ûpᵉṭûrê ṣîṣîm</strong>: 'He carved on them cherubim, palms, and open flowers, and overlaid them with gold' — the two olive-wood doors of the inner sanctuary carried the full carved program of the interior walls: cherubim, palms, and flowers. The doors were the first point of visual encounter for those approaching the Holy of Holies — the carved program announced the Eden-sanctuary before the viewer entered.</p>",
    "33": "<p><strong>wᵉḵēn ʿāśāh lᵉpetaḥ hahêḵāl mezûzôṯ ʿaṣê šāmen rᵉḇîʿîṯ</strong>: 'So also he made for the entrance of the main hall door-frames of olive wood — a fourth part' — the main hall's entrance had a four-sided (rectangular) frame, as opposed to the inner sanctuary's five-sided frame. The differentiated frame shapes (five-sided for the debir, four-sided for the hekhal) may signal the graduated sanctity of the two spaces.</p>",
    "34": "<p><strong>ûšᵉtê daltôṯ ʿaṣê bᵉrôšîm</strong>: 'The two doors were of cypress wood' — the main hall's doors were cypress (<em>bᵉrôšîm</em>) rather than olive wood; the inner sanctuary's doors were olive wood. The use of different woods for the two doors may encode a distinction in sanctity, or reflect material availability. The two-leaf arrangement of each door (two halves, each half folding) created a flexible entry system for the Temple's regular priestly use.</p>",
    "35": "<p><strong>wᵉqālaʿ kᵉrûḇîm wᵉtîmōrōṯ ûpᵉṭûrê ṣîṣîm ûmᵉṣuppeh zāhāḇ mûšāh ʿal-hamᵉḥuqqeh</strong>: 'He carved cherubim, palms, and open flowers, and overlaid them with gold fitted on the carved work' — the gold was not simply applied as sheets but hammered to fit the relief carvings of the cypress doors. This goldsmithing technique (<em>mûšāh ʿal-hamᵉḥuqqeh</em>, gold set/fitted over the carved relief) shows a high level of craft: the carved decoration was preserved in three dimensions beneath the gold sheathing.</p>",
    "36": "<p><strong>wayyibᵉn ʾeṯ-heḥāṣēr happᵉnîmîṯ</strong>: 'He built the inner court with three courses of dressed stone and one course of cedar beams' — the inner court surrounding the Temple proper used alternating courses of stone and cedar in a ratio of 3:1. This construction method reflects Solomonic building practice learned from Phoenician craftsmen. The inner court (<em>ḥāṣēr happᵉnîmîṯ</em>) corresponds to the tabernacle's courtyard enclosing the sacred precinct.</p>",
    "37": "<p><strong>bišnaṯ hārbîʿîṯ yussad bêṯ YHWH bᵉyeraḥ ziw</strong>: 'In the fourth year the house of YHWH was founded, in the month of Ziv' — the construction record gives both the starting date (v37) and the completion date (v38) with month names. Ziv (the second month) is the Canaanite name for the month; the post-exilic designation is Iyyar. The specific month naming grounds the Temple's construction in historical time — not mythological time — a feature that distinguishes Israelite historiography from neighboring ANE building accounts which typically locate temple constructions in cosmic rather than historical time.</p>",
    "38": "<p><strong>ûbiššᵉnāh hāʾaḥaṯ ʿeśrēh bᵉyeraḥ bûl hûʾ haḥōdeš hašᵉmînî kālāh habbayiṯ lᵉḵol-dᵉḇārāyw wᵉḵol-mišpāṭāyw wayyibᵉnēhû šeḇaʿ šānîm</strong>: 'In the eleventh year, in the month of Bul — the eighth month — the house was completed in every detail according to all its specifications. He built it in seven years.' The completion in seven years is the structural signature of the narrative: seven years = the number of divine completion (Gen 2:1-3, the seventh day of creation rest). The Temple built in the number of completion consecrates it as the earthly counterpart of YHWH's cosmic dwelling established at creation. Bul (the eighth month, post-exilic: Ḥeshvan) grounds the completion in the agricultural year's early rainy season.</p>"
  },
  "7": {
    "1": "<p><strong>ûšᵉlōmōh hāyāh bōneh ʾeṯ-bêṯô šᵉlōš ʿeśrēh šānāh</strong>: 'Solomon was building his own house thirteen years' — Solomon's palace took thirteen years to complete vs. seven years for the Temple (6:38). The juxtaposition is deliberate: ch 6 ends with the Temple's seven-year completion; ch 7 immediately notes the palace took nearly twice as long. Ancient readers would have heard this as a significant inversion of priorities — a warning that echoes throughout the Deuteronomistic History's evaluation of Solomon.</p>",
    "2": "<p><strong>wayyibᵉn ʾeṯ-bêṯ yaʿar hallᵉḇānôn</strong>: 'He built the House of the Forest of Lebanon' — the palace complex's main hall, named for its four rows of cedar pillars creating the visual effect of a forest. Its dimensions: 100 × 50 × 30 cubits. Compare the Temple: 60 × 20 × 30 cubits. The House of the Forest of Lebanon was larger than the Temple in ground area and matched it in height — a disproportion the narrative records without comment but clearly intended to be noticed. It served as an armory (1 Kgs 10:17; Isa 22:8) and reception hall.</p>",
    "3": "<p><strong>wᵉsāpûn ʾārez mimmāʿal ʿal-ṣᵉlāʿôṯ</strong>: 'It was roofed with cedar above the beams on the pillars' — the forest imagery was created by 45 cedar pillars (three rows of 15, v2) rising to a cedar ceiling. The abundant use of Phoenician cedar (the most expensive and prestigious building material of the era) for the palace is the material expression of Solomon's imperial wealth — the same cedar that sanctified the Temple now furnishes the royal apartments.</p>",
    "4": "<p><strong>wᵉšᵉqûpîm šᵉlōšāh ṭûrîm</strong>: 'Windows in three rows' — the House of the Forest of Lebanon had three rows of windows on each side, arranged in symmetrical facing pairs. The architectural vocabulary (<em>šᵉqûpîm</em>, lattice windows) is the same used for the Temple in 6:4, reflecting the same building tradition across both structures.</p>",
    "5": "<p><strong>wᵉkol-hapᵉtāḥîm wᵉhamᵉzûzôṯ rᵉbûʿîm šāqep</strong>: 'All the doorways and window frames were square' — the consistency of rectangular/square frames throughout the palace maintained the geometric order that characterized Solomonic monumental architecture. Square-framed openings (<em>rᵉbûʿîm</em>) were the standard of precision construction, indicating the palace was built to the same exacting specifications as the Temple.</p>",
    "6": "<p><strong>wᵉʾêlām hāʿammûdîm ʿāśāh</strong>: 'He made the hall of pillars' — the porch of pillars (50 × 30 cubits) served as a transitional space between the House of the Forest of Lebanon and the main palace. The term <em>ʾêlām</em> (porch, hall) is used also for the Temple's vestibule (6:3), indicating the palace's public entrance used the same architectural vocabulary as the Temple — the king's residence designed to parallel the divine residence in form.</p>",
    "7": "<p><strong>wᵉʾêlām hakkissēʾ ʾăšer yišpōṭ-šām</strong>: 'The hall of the throne where he was to judge' — Solomon's judgment hall was a royal court where the king dispensed justice. The throne for judgment (<em>kissēʾ mišpāṭ</em>) is the earthly embodiment of the principle that YHWH is the ultimate judge (Ps 9:4) — the Davidic king sits in judgment as YHWH's vice-regent, accountable to the covenant standards he is meant to enforce.</p>",
    "8": "<p><strong>ûḇêṯô ʾăšer-yēšeḇ šām ḥāṣēr hāʾaḥereṯ mibbayyiṯ lāʾûlām</strong>: 'His house where he dwelt — the other court inside the porch' — Solomon's private quarters maintained separation between the official and personal zones of the palace. The mention of Pharaoh's daughter's separate house (v8b) is the narrative's first explicit reminder of Solomon's Egyptian marriage (3:1) and its ongoing presence at the heart of the royal complex.</p>",
    "9": "<p><strong>kol-ʾēlleh ʾăḇānîm yᵉqārôṯ kᵉmiddôṯ gāzîṯ mᵉgōrāreṯ bammᵉgērāh</strong>: 'All these were of costly stones cut according to measure, dressed with the saw' — the palace complex used dressed limestone blocks (<em>ʾăḇānîm yᵉqārôṯ</em>, costly/precious stones) sawn with metal saws. The same quality of construction was applied to the palace as to the Temple — both used pre-cut stone dressed to measurement, likely by the same craftsmen.</p>",
    "10": "<p><strong>yᵉsōdôṯ ʾăḇānîm yᵉqārôṯ ʾăḇānîm gᵉḏōlôṯ</strong>: 'The foundation was of costly stones, great stones' — the palace's foundation stones were enormous: 8 and 10 cubits (12-15 feet) in length. Foundation stones of this size are confirmed by archaeology at Megiddo and other Solomonic-era sites. The emphasis on the foundations' solidity reflects the ANE concept that a building's quality was expressed from the ground up — massive foundation stones guaranteed structural permanence.</p>",
    "11": "<p><strong>ûlᵉmaʿlāh ʾăḇānîm yᵉqārôṯ kᵉmiddôṯ gāzîṯ ûʾārez</strong>: 'Above were costly stones of specified measure and cedar' — the superstructure alternated dressed stone courses with cedar, the same pattern used for the inner court of the Temple (6:36: three courses of stone to one of cedar). The structural continuity between Temple and palace architecture reflects a unified building program for Solomon's entire Jerusalem complex.</p>",
    "12": "<p><strong>wᵉheḥāṣēr haggᵉḏôlāh sāḇîḇ šᵉlōšāh ṭûrîm gāzîṯ wᵉṭûr kᵉrōṯ ʾarāzîm</strong>: 'The great court surrounding had three courses of dressed stone and one course of cedar beams' — the outer court enclosing the entire royal complex used the same 3:1 stone-to-cedar construction as both the Temple's inner court (6:36) and the palace's stone-and-cedar courses (v11). The structural formula creates visual and material continuity across the entire Solomonic building complex on Jerusalem's eastern hill, unifying the sacred and royal precincts under one architectural vocabulary.</p>",
    "13": "<p><strong>wayyišlaḥ hammelek šᵉlōmōh wayyiqqaḥ ʾeṯ-ḥîrām miṣṣōr</strong>: 'King Solomon sent and brought Hiram from Tyre' — this Hiram (not to be confused with Hiram king of Tyre in ch 5) is the master craftsman. He appears as <em>Hûrām ʾāḇî</em> (Huram-abi) in 2 Chr 2:13, meaning 'Huram my father/master,' indicating he was regarded as the definitive craftsman-expert.</p>",
    "14": "<p><strong>ben-ʾiššāh ʾalmānāh hûʾ mimaṭṭēh naptālî wayyimmālēʾ ʾeṯ-haḥoḵmāh ûḇattᵉḇûnāh wᵉhaddaʿaṯ</strong>: 'Son of a widow from the tribe of Naphtali; he was filled with wisdom, understanding, and skill' — the three elements of Hiram's description echo Bezalel (Exod 31:2-5): tribe identification, craftsman lineage, and divine filling for skilled work. Bezalel was 'filled with the Spirit of God, with wisdom, understanding, and knowledge' (<em>wayyᵉmallēʾ ʾōṯô rûaḥ ʾĕlōhîm bᵉḥoḵmāh</em>); Hiram is <em>wayyimmālēʾ ʾeṯ-haḥoḵmāh ûḇattᵉḇûnāh wᵉhaddaʿaṯ</em>. The explicit parallel signals that the Temple's construction draws on the same divine enablement as the tabernacle — craft wisdom is a divine gift, not merely human skill. Hiram's Gentile heritage (Tyrian father) continues the pattern of God-gifted craftsmen working across ethnic boundaries for the sacred.</p>",
    "15": "<p><strong>wayyāṣōr ʾeṯ-šᵉnê hāʿammûdîm nᵉḥōšeṯ</strong>: 'He cast two bronze pillars' — the two bronze pillars were cast in the Jordan plain (v46), each 18 cubits (27 feet) tall with a circumference of 12 cubits (18 feet). The casting of such large hollow bronze columns required advanced metallurgy: preparing clay molds, maintaining consistent heat across large areas, and managing the cooling process without structural failure. The Jordan Valley's clay beds provided ideal mold material.</p>",
    "16": "<p><strong>wᵉšᵉnê kaptōrôṯ yᵉṣûqôṯ nᵉḥōšeṯ</strong>: 'He made two capitals of cast bronze' — the capitals (<em>kaptōrôṯ</em>) were the decorative tops of the pillars, each 5 cubits (7.5 feet) tall. The term <em>kaptōr</em> means 'knob' or 'button' and is used also for the golden knobs on the tabernacle's lampstand (Exod 25:31-36), maintaining the architectural vocabulary connecting Temple and tabernacle furnishings.</p>",
    "17": "<p><strong>śᵉbāḵôṯ maʿăśēh šᵉḇeṯ śᵉrugîm lakkaptōrôṯ</strong>: 'Latticework and chains for the capitals' — the capitals were decorated with interwoven lattice-work (<em>śᵉḇāḵôṯ</em>, nets/lattices) and hanging chains (<em>śᵉrugîm</em>, interwoven/braided cords), seven for each capital. The decorative program combined openwork lattice with hanging garlands that descended from the capitals, creating a visual richness suited to marking the Temple's entrance.</p>",
    "18": "<p><strong>wᵉʾeṯ-hāʿammûdîm ûšᵉnê ṭûrîm sāḇîḇ ʿal-haśśeḵāḵ hāʾeḥāṯ</strong>: 'He made the pillars and two rows around upon the one latticework' — the pillar capitals bore two rows of pomegranates (<em>rimmônîm</em>) arranged around the lattice network. Pomegranates appear throughout the tabernacle's decorative program: on the high priest's robe hem (Exod 28:33-34). They symbolize the covenant blessings and abundance of the promised land — their placement at the Temple's entrance declares the sanctuary as the source of covenant blessing.</p>",
    "19": "<p><strong>wᵉhakkaptōrôṯ ʾăšer ʿal-rōʾš hāʿammûdîm maʿăśēh šôšan</strong>: 'The capitals on top of the pillars were of lily design' — the capitals in the portico were designed as stylized lilies (<em>maʿăśēh šôšan</em>). Lily designs appear extensively in ancient Near Eastern sacred art and throughout the Temple decorative program. The lily (<em>šôšan</em>) appears also in the Song of Solomon as a symbol of covenant beauty and in royal psalms. The botanical program — lilies, palms, pomegranates, flowers — creates a pervasive garden-of-Eden aesthetic at every entrance.</p>",
    "20": "<p><strong>wᵉhakkaptōrôṯ ʿal-šᵉnê hāʿammûdîm… rimmōnîm maʾtayim ṭûrîm sāḇîḇ</strong>: 'The capitals on both pillars had 200 pomegranates in rows around each capital' — 200 pomegranates on each capital (Jer 52:23 gives 96 visible, suggesting some were on the underside of the lattice — the 400 total includes these hidden ones). The pomegranate program on the Temple pillars is the most extensive ornamental use of this symbol in the OT, marking the Temple's entrance as the threshold of covenant abundance.</p>",
    "21": "<p><strong>wayyāqem ʾeṯ-hāʿammûḏ hayᵉmânî wayyiqrāʾ ʾeṯ-šᵉmô yāḵîn… wayyiqrāʾ ʾeṯ-šᵉmô bōʿaz</strong>: 'He erected the right pillar and named it Jachin… he named the left pillar Boaz' — the names of the pillars are theologically programmatic: <em>Yāḵîn</em> (Jachin) = 'He establishes / He will establish'; <em>Bōʿaz</em> (Boaz) = 'In him is strength' (or 'With the strength [of YHWH]'). Together: 'He establishes in/with strength.' Every worshiper entering the Temple passed through this named declaration of YHWH's covenantal steadfastness and power. Jachin also evokes the Davidic covenant word (<em>kûn</em>, establish; 2 Sam 7:12-16).</p>",
    "22": "<p><strong>wᵉʿal-rōʾš hāʿammûdîm maʿăśēh šôšan wayyittam mᵉlāʾḵeṯ hāʿammûdîm</strong>: 'On top of the pillars was lily-work. So the work of the pillars was finished' — the lily-crowned tops completed the botanical ascent: pomegranates in the middle register, lilies at the crown. Entering the Temple meant passing beneath these crowned pillars — an architectural blessing in botanical and onomastic language. <em>Wayyittam</em> (from <em>tāmam</em>, to be complete, perfect) uses the language of perfect completion, appropriate for the threshold of YHWH's dwelling.</p>",
    "23": "<p><strong>wayyaʿaś ʾeṯ-hayyām mûṣāq ʿeśer bāʾammāh miśśāpāṯô ʾad-śāpāṯô</strong>: 'He made the Sea of cast metal, ten cubits from brim to brim' — the <em>yām mûṣāq</em> (molten/cast Sea) was a massive circular bronze basin 10 cubits (15 feet) in diameter, 5 cubits deep, 30 cubits in circumference. The choice of <em>yām</em> (sea) as the name is theologically loaded: in the ancient Near East the primordial <em>yam</em> was the chaotic cosmic waters defeated by the creator deity. The Temple's bronze Sea represents the chaotic waters subdued and made to serve YHWH's purposes — wild water tamed and contained for priestly purification.</p>",
    "24": "<p><strong>ûpᵉqāʿîm mittaḥaṯ lᵉśāpāṯô sāḇîḇ</strong>: 'Under its rim around were gourds' — the <em>pᵉqāʿîm</em> (gourds/knobs) arranged in two rows around the rim of the Sea are the same decorative element as in the Temple interior (6:18). The botanical decorative program continued on the bronze furnishings, maintaining the Eden-garden imagery across all scales of the Temple complex.</p>",
    "25": "<p><strong>ʿōmēd ʿal-šᵉnê ʿāśār bāqār šᵉlōšāh pōnîm ṣāpônāh</strong>: 'It stood on twelve oxen, three facing north, three facing west, three facing south, three facing east' — the twelve bronze oxen supporting the Sea face outward in four groups of three, covering all four compass directions. Twelve is the number of the tribes of Israel. The four-directional arrangement represents the four-corners cosmology — YHWH's sovereignty over the complete creation. The Sea thus stands at the intersection of the twelve-tribe covenant community and the four-direction cosmos: the Temple as the axis mundi, the point where heaven and earth meet.</p>",
    "26": "<p><strong>ûśpāṯô kᵉmaʿăśēh śpat kôs pᵉraḥ šôšan ʾalpayim baṯ yāḵîl</strong>: 'Its rim was made like the rim of a cup, like the flower of a lily; it held 2,000 baths' — the Sea's capacity was 2,000 baths (approximately 12,000 gallons). 2 Chr 4:5 gives 3,000 baths; the discrepancy may reflect the distinction between maximum capacity and practical working capacity. The rim fashioned as a lily blossom (<em>pᵉraḥ šôšan</em>) continues the botanical motif: the vessel for ritual purification is itself a flower — ablution and beauty are not separated in the Temple's design.</p>",
    "27": "<p><strong>wayyaʿaś ʾeṯ-ʿeśer hamᵉkônôṯ nᵉḥōšeṯ</strong>: 'He made the ten bronze stands' — the ten wheeled water-stands (<em>mᵉkônôṯ</em>) were mobile bronze trolleys designed to transport water from the Sea to the various ritual washing stations. Each stand was 4 × 4 × 3 cubits, with wheeled bases for mobility. The engineering sophistication of these portable bronze stands explains why the Babylonians specifically cut away the bronze work when destroying the Temple (2 Kgs 25:13-16).</p>",
    "28": "<p><strong>wᵉzeh maʿăśēh hamᵉkônāh</strong>: 'This was the construction of the stands' — the detailed description of the stands' construction (vv28-37) reflects the same meticulous record-keeping as the Mosaic tabernacle (Exod 36-39). The architectural/technical precision of the Kings narrative derives from official building records kept in the royal archives, serving both archival and legal functions — accountability for the sacred treasures of the Temple.</p>",
    "29": "<p><strong>wᵉʿal-hammisgᵉrôṯ ʾăšer bên hāšᵉlabbîm ʾărāyôṯ bāqār ûkᵉrûḇîm</strong>: 'On the frames between the crossbars were lions, oxen, and cherubim' — the three figures decorating the stand panels (lions, oxen, cherubim) are the same figures associated with the divine throne-chariot in Ezekiel's vision (Ezek 1:10: the four living creatures; Rev 4:7: the same four faces). The Temple furnishings carry the same symbolic vocabulary as the later theophanic vision — the mobile stands encircling the Sea are a microcosm of the divine presence-throne.</p>",
    "30": "<p><strong>wᵉʾarbaʿāh ʾôpannê nᵉḥōšeṯ lammᵉkônāh hāʾaḥāṯ</strong>: 'Each stand had four bronze wheels' — the wheeled stands were functional as well as decorative: the wheels (<em>ʾôpannîm</em>, same term used for Ezekiel's throne-chariot wheels in Ezek 10:9-13) allowed the stands to be moved around the Temple court. The functional bronze stands carrying water for ritual purity are thus architecturally echoing the divine chariot — the Temple's working equipment participates in the throne-chariot imagery of YHWH's mobile presence.</p>",
    "31": "<p><strong>ûpîhû mibbayyiṯ lakkaptōreṯ wāmāʿlāh bāʾammāh</strong>: 'Its opening within the capital at the top was one cubit' — the stand's central basin had a circular opening 1.5 cubits in diameter. The technical vocabulary (<em>kaptōreṯ</em>, capital; <em>peh</em>, opening/mouth) reflects the same terminology used for the pillar capitals and the lampstand — the Temple complex's furnishings form a unified lexical system.</p>",
    "32": "<p><strong>wᵉhaʾôpannîm ʾarbaʿāh mittaḥaṯ lammišgᵉrôṯ</strong>: 'The four wheels were under the frames' — the wheelbase design of the stands: the four wheels were fixed beneath the lower frame, which supported the upper decorative frames. The detailed description of the wheeled base enables a modern mechanical understanding of the stands' function: they were designed to roll on flat stone surfaces, allowing priests to position the water basins exactly where needed for the various sacrificial rituals.</p>",
    "33": "<p><strong>ûmaʿăśēh hāʾôpannîm kᵉmaʿăśēh ʾôpan hammerkāḇāh</strong>: 'The construction of the wheels was like the construction of a chariot wheel' — the bronze wheels were made like chariot wheels (<em>merkāḇāh</em>), with spokes, felloes (rim segments), hubs, and tires — all cast in bronze. The chariot-wheel construction for Temple stands is another convergence of the military and the sacred: the most sophisticated mobile technology of the era (the war chariot) is repurposed for the Temple's service.</p>",
    "34": "<p><strong>wᵉʾarbaʿāh kêṯpôṯ ʾel-ʾarbaʿat pōʾôṯ hamᵉkônāh hāʾaḥāṯ</strong>: 'There were four shoulders at the four corners of each stand' — the structural shoulders (<em>kêṯpôṯ</em>, literally 'shoulders') at each corner served as structural anchor points connecting the upper decorative panels to the wheel-bearing lower frame. The anatomical vocabulary for structural joints reflects the OT's tendency to describe architectural elements in body terms (cf. <em>yāḏôṯ</em>, hands, for shaft/axles in v32).</p>",
    "35": "<p><strong>ûbᵉrōʾš hamᵉkônāh ḥᵉṣî hāʾammāh qômāh</strong>: 'At the top of the stand was a half-cubit high rounded support' — the top of each stand had a circular rim half a cubit tall that held the laver basin in place. The architectural precision — half-cubit measurements, squared shoulders, connecting pieces — reflects the same engineering discipline as the Mosaic tabernacle's construction, where fractional cubit dimensions were also specified.</p>",
    "36": "<p><strong>wayyᵉpattaḥ ʿal-lûḥōṯ šiḇḥêhā kᵉrûḇîm ʾărāyôṯ wᵉtîmōrōṯ</strong>: 'He engraved on the panels cherubim, lions, and palm trees' — the decorative panels of the stands carried three of the four major recurring Temple motifs: cherubim (divine guardians), lions (royal power), and palms (Eden abundance). The stands are miniature temples: each one carries the complete symbolic program of the larger Temple, making the entire furnishing system a coherent theological statement.</p>",
    "37": "<p><strong>kāzōʾṯ ʿāśāh ʾēṯ ʿeśer hamᵉkônôṯ mûṣāq ʾeḥāḏ middāh ʾaḥaṯ qᵉṣāḇāh ʾaḥāṯ lᵉkullānāh</strong>: 'In this manner he made the ten stands — all of them had the same casting, the same measure, the same form' — the standardization of the ten stands is explicitly noted: identical measurements, identical casting, identical form. Standardization in sacred objects was required for liturgical equity — no stand's laver was larger or more elaborate than another's. The identical-cast stands embody the principle of equal access to YHWH's purifying water for all priestly service.</p>",
    "38": "<p><strong>wayyaʿaś ʿeśer kiyyōrôṯ nᵉḥōšeṯ ʾarbaʿîm baṯ yāḵîl hakkiyyôr hāʾeḥāḏ ʾarbaʿ bāʾammāh</strong>: 'He made ten bronze lavers, each holding forty baths' — the ten bronze lavers (<em>kiyyōrôṯ</em>) were the water basins placed on the ten stands. Each held 40 baths (approximately 240 gallons). Their placement: five on the south side of the Temple, five on the north side (v39). The lavers were used for washing the burnt offerings (2 Chr 4:6), while the great Sea was for priestly washing (2 Chr 4:6). The functional system — Sea for priests, lavers for sacrifices — maintained the distinction between the cleansing of those who serve and the preparation of what they offer.</p>",
    "39": "<p><strong>wayyittēn ʾeṯ-hamᵉkônôṯ ḥāmēš ʿal-kātēp habbayiṯ hayyᵉmânîṯ wᵉḥāmēš ʿal-kātēp habbayiṯ haśśᵉmāʾlîṯ</strong>: 'He placed five stands on the south side of the house and five on the north side' — the symmetrical arrangement of the ten stands (five south, five north) flanking the Temple expressed cosmic completeness: north and south, covering both halves of the sacred precinct. The Sea was placed at the south-east corner (2 Chr 4:10). The spatial arrangement transformed the Temple court into a structured liturgical space where every functional element was positioned according to a designed order.</p>",
    "40": "<p><strong>wayyaʿaś ḥîrām ʾeṯ-hakkiyyōrôṯ wᵉʾeṯ-hayyāʿîm wᵉʾeṯ-hammizrāqôṯ</strong>: 'Hiram made the lavers, the pots, and the basins' — verse 40 summarizes Hiram's complete bronze-work production: lavers (<em>kiyyōrôṯ</em>), pots (<em>yᵉʿîm</em>, for removing ashes), and basins (<em>mizrāqôṯ</em>, for blood and water sprinkling). These three vessel types encompass the complete functional range of priestly service: water for purification, ash-removal for altar maintenance, and blood-basins for sacrificial ritual.</p>",
    "41": "<p><strong>wᵉʾeṯ-šᵉnê hāʿammûdîm wᵉʾeṯ-gullôṯ hakkaptōrôṯ</strong>: 'The two pillars, and the bowl-shaped capitals on top of the two pillars' — v41 begins the summary inventory of all Hiram's bronze work (vv41-47). The <em>gullôṯ</em> (bowl-shaped capitals) are the rounded upper portions of the pillar capitals; the term is used also for the oil-basin of the lampstand in Zech 4:2. The summary inventory serves both archival and theological purposes: cataloguing what was made creates a permanent record of the Temple's sacred furnishings.</p>",
    "42": "<p><strong>wᵉʾarbaʿ meʾôṯ rimmōnîm lišᵉtê haśśeḵāḵôṯ</strong>: '400 pomegranates for the two networks' — the summary confirms 200 pomegranates per pillar capital (two rows on each latticework), for a total of 400. The pomegranate count in the summary matches the construction account, providing internal verification of the building record.</p>",
    "43": "<p><strong>wᵉʾeṯ-ʿeśer hamᵉkônôṯ wᵉʾeṯ-ʿeśer hakkiyyōrôṯ ʿal-hamᵉkônôṯ</strong>: 'The ten stands and the ten lavers on the stands' — the summary continues with the stands and their lavers. The 1:1 ratio (one laver per stand) made each stand-laver combination a self-contained purification unit that could be positioned independently around the Temple court — a modular design reflecting the Temple's operational flexibility.</p>",
    "44": "<p><strong>wᵉʾeṯ-hayyām hāʾeḥāḏ wᵉʾeṯ-habbāqār šᵉnêm ʿāśār taḥaṯ hayyām</strong>: 'The one Sea, and the twelve oxen under the Sea' — the molten Sea and its twelve supporting oxen are summarized together as a single unit. The twelve oxen are structurally integral to the Sea — they are its base. The summary's pairing confirms the design intention: the Sea cannot be understood apart from its cosmological support structure (twelve tribes, four directions).</p>",
    "45": "<p><strong>wᵉʾeṯ-hassîrôṯ wᵉʾeṯ-hayyāʿîm wᵉʾeṯ-hamizrāqôṯ</strong>: 'The pots, the shovels, and the basins' — the summary repeats the functional bronze vessels: <em>hassîrôṯ</em> (pots/caldrons) for boiling; <em>hayyāʿîm</em> (ash-shovels); <em>hamizrāqôṯ</em> (blood-basins). All these vessels were of burnished (<em>mᵉmōrāṭ</em>) bronze — polished to a mirror finish, reflecting the dedication to beauty in every functional object of the Temple.</p>",
    "46": "<p><strong>bᵉḵikkār hayyadrēn yᵉṣāqām hammelek bᵉmaʿᵃbēh hāʾădāmāh bên sukkôṯ ûbên ṣārᵉṯān</strong>: 'In the plain of the Jordan the king cast them, in the clay ground between Succoth and Zarethan' — the large bronze castings were made in the Jordan Valley, where the clay soil was ideal for bronze-casting molds. The casting site's distance from Jerusalem (approximately 30 miles) explains why the bronze work was pre-fabricated off-site and transported to Jerusalem, paralleling the Temple's pre-cut stones (6:7).</p>",
    "47": "<p><strong>wayyanniaḥ šᵉlōmōh ʾeṯ-kol-hakkēlîm mippᵉnê rōḇ mᵉʾōḏ lōʾ neḥqar mišqal hannᵉḥōšeṯ</strong>: 'Solomon left all the vessels unweighed, because there were so many; the weight of the bronze was not determined' — the bronze was so abundant that Solomon did not weigh it — an expression of extraordinary material excess. The quantity reflects David's preparatory accumulation (1 Chr 22:3: 'David provided iron in abundance for the nails for the doors… bronze in quantities beyond weighing').</p>",
    "48": "<p><strong>wayyaʿaś šᵉlōmōh ʾēṯ kol-hakkēlîm ʾăšer bêṯ YHWH ʾēṯ mizbaḥ hazzāhāḇ</strong>: 'Solomon also made all the vessels in the house of the LORD: the golden altar' — the shift from bronze (vv13-47) to gold marks the transition from outer-court furnishings to inner-Temple furnishings. The golden altar (<em>mizbaḥ hazzāhāḇ</em>) is the incense altar that stood before the entrance to the Holy of Holies — the direct descendant of the golden incense altar of the tabernacle (Exod 30:1-10), which Hebrews 9:4 theologically locates inside the veil.</p>",
    "49": "<p><strong>wᵉʾeṯ-mᵉnōrôṯ hazzāhāḇ hazzāḵ ḥāmēš miyyāmîn wᵉḥāmēš miśśᵉmōʾl lifᵉnê haddebîr</strong>: 'The ten lampstands of pure gold, five on the right and five on the left before the inner sanctuary' — the ten golden lampstands replaced the single tabernacle lampstand. Their arrangement — five on each side flanking the approach to the Holy of Holies — multiplied the sevenfold light of the single tabernacle lampstand (Exod 25:31-40) tenfold. The tabernacle's one lampstand represented divine light in the portable wilderness community; the Temple's ten lampstands represent the fullness of divine light in the settled covenant dwelling.</p>",
    "50": "<p><strong>wᵉhappᵉrāḥîm wᵉhannērôṯ wᵉhamᵉlaqāḥayim… kol-kᵉlî hazzāhāḇ sāgûr</strong>: 'The flower decorations, lamps, tongs, cups, snuffers, basins, dishes, and fire-holders — all of pure gold' — the complete list of gold furnishings covers every functional object needed for priestly service in the Temple. The insistence on pure gold (<em>zāhāḇ sāgûr</em>) for even the functional implements signals that in YHWH's house no object is merely utilitarian — every implement is sacred.</p>",
    "51": "<p><strong>wayyišlam kol-hammᵉlāʾḵāh ʾăšer ʿāśāh hammelek šᵉlōmōh bêṯ YHWH wayyāḇēʾ šᵉlōmōh ʾeṯ-qoḏšê dāwîd ʾāḇîw ʾeṯ-hakkesep wᵉʾeṯ-hazzāhāḇ wᵉʾeṯ-hakkēlîm nāṯan bᵉʾōṣᵉrôṯ bêṯ YHWH</strong>: 'All the work that King Solomon did on the house of the LORD was complete. And Solomon brought in the things David his father had dedicated — the silver, the gold, and the vessels — and stored them in the treasuries of the house of the LORD.' The chapter closes with two completions: Solomon's work and David's legacy. The transfer of David's dedicated treasures — accumulated over a lifetime of war and preparation (1 Chr 22, 28-29) — into the Temple treasuries signals the continuity of the Davidic covenant purpose. David prepared; Solomon built. The Temple is the product of two generations of covenant faithfulness, embodying the pattern of divine promise running from generation to generation in the Davidic line that ultimately flows to 'great David's greater son.'</p>"
  }
}

def main():
    c = load_comm('mkt-original', '1kings')
    merge_comm(c, KINGS1)
    save_comm('mkt-original', '1kings', c)
    count = sum(len(v) for v in KINGS1.values())
    print(f'1 Kings 6–7 mkt-original: {count} verses written')

if __name__ == '__main__':
    main()
